import{c as n,S as a,j as t,m as h}from"./chunks/framework.8aa1YH_s.js";const d=JSON.parse('{"title":"Xem lại bài thi","description":"","frontmatter":{},"headers":[],"relativePath":"hoc-vien/xem-lai-bai-thi.md","filePath":"hoc-vien/xem-lai-bai-thi.md","lastUpdated":0}'),l={name:"hoc-vien/xem-lai-bai-thi.md"};function c(o,i,r,e,g,u){return a(),t("div",null,[...i[0]||(i[0]=[h('<h1 id="xem-lai-bai-thi" tabindex="-1">Xem lại bài thi <a class="header-anchor" href="#xem-lai-bai-thi" aria-label="Permalink to “Xem lại bài thi”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/luyen-tap/xem-lai/:id</code></p><p><strong>Xem lại</strong> là bước <strong>học tập quan trọng nhất</strong> sau khi nộp bài. Đừng chỉ nhìn điểm số - hãy <strong>đọc kỹ từng câu sai</strong> để cải thiện.</p><h2 id="truy-cap-trang-xem-lai" tabindex="-1">Truy cập trang xem lại <a class="header-anchor" href="#truy-cap-trang-xem-lai" aria-label="Permalink to “Truy cập trang xem lại”">​</a></h2><h3 id="ngay-sau-khi-nop-bai" tabindex="-1">Ngay sau khi nộp bài <a class="header-anchor" href="#ngay-sau-khi-nop-bai" aria-label="Permalink to “Ngay sau khi nộp bài”">​</a></h3><ul><li>Trang Kết quả có nút <strong>Xem lại bài</strong>.</li></ul><h3 id="sau-nay-tu-lich-su" tabindex="-1">Sau này (từ lịch sử) <a class="header-anchor" href="#sau-nay-tu-lich-su" aria-label="Permalink to “Sau này (từ lịch sử)”">​</a></h3><ul><li>Vào <strong>Hồ sơ cá nhân → Lịch sử thi</strong> hoặc trong khóa → tab Lịch sử.</li><li>Bấm vào dòng bài muốn xem.</li></ul><h2 id="giao-dien-trang-xem-lai" tabindex="-1">Giao diện trang xem lại <a class="header-anchor" href="#giao-dien-trang-xem-lai" aria-label="Permalink to “Giao diện trang xem lại”">​</a></h2><p>Hiển thị từng câu:</p><h3 id="đe-cau-hoi" tabindex="-1">Đề câu hỏi <a class="header-anchor" href="#đe-cau-hoi" aria-label="Permalink to “Đề câu hỏi”">​</a></h3><ul><li>Nguyên văn câu hỏi (chữ, hình ảnh, công thức).</li></ul><h3 id="đap-an-ban-chon" tabindex="-1">Đáp án bạn chọn <a class="header-anchor" href="#đap-an-ban-chon" aria-label="Permalink to “Đáp án bạn chọn”">​</a></h3><ul><li><strong>Tô màu xanh</strong> nếu đúng, <strong>đỏ</strong> nếu sai.</li></ul><h3 id="đap-an-đung" tabindex="-1">Đáp án đúng <a class="header-anchor" href="#đap-an-đung" aria-label="Permalink to “Đáp án đúng”">​</a></h3><ul><li>Hiển thị rõ đáp án chuẩn.</li></ul><h3 id="loi-giai-chi-tiet" tabindex="-1">Lời giải chi tiết <a class="header-anchor" href="#loi-giai-chi-tiet" aria-label="Permalink to “Lời giải chi tiết”">​</a></h3><ul><li>Nếu giáo viên đăng, có <strong>lời giải step-by-step</strong>.</li><li>Bao gồm: cách suy luận, công thức, kết quả.</li></ul><h3 id="cau-hoi-lien-quan-goi-y" tabindex="-1">Câu hỏi liên quan (gợi ý) <a class="header-anchor" href="#cau-hoi-lien-quan-goi-y" aria-label="Permalink to “Câu hỏi liên quan (gợi ý)”">​</a></h3><ul><li>Hệ thống có thể gợi ý các câu <strong>cùng chủ đề</strong> để bạn luyện thêm.</li></ul><h2 id="loc-cau" tabindex="-1">Lọc câu <a class="header-anchor" href="#loc-cau" aria-label="Permalink to “Lọc câu”">​</a></h2><p>Trên đầu trang có bộ lọc:</p><ul><li><strong>Tất cả</strong> (mặc định)</li><li><strong>Chỉ câu sai</strong></li><li><strong>Chỉ câu đúng</strong></li><li><strong>Câu bỏ trống</strong></li><li><strong>Câu đã đánh dấu</strong></li><li><strong>Theo chủ đề</strong></li></ul><blockquote><p>💡 Tập trung xem <strong>câu sai</strong> trước - đó là nơi học được nhiều nhất.</p></blockquote><h2 id="đat-cau-hoi-cho-giao-vien-ngay-tai-cau" tabindex="-1">Đặt câu hỏi cho giáo viên ngay tại câu <a class="header-anchor" href="#đat-cau-hoi-cho-giao-vien-ngay-tai-cau" aria-label="Permalink to “Đặt câu hỏi cho giáo viên ngay tại câu”">​</a></h2><p>Mỗi câu có nút <strong>Đặt câu hỏi / Hỏi giáo viên</strong>:</p><ol><li>Bấm → khung Hỏi đáp mở ra.</li><li>Gõ câu hỏi của bạn (vd &quot;Thầy ơi, vì sao đáp án không phải D? Em nghĩ là D&quot;).</li><li>Đính kèm ảnh / file nếu cần.</li><li>Gửi.</li><li>Giáo viên trả lời → bạn nhận thông báo.</li></ol><p>→ Xem <a href="./hoi-dap">Hỏi đáp với giáo viên</a>.</p><h2 id="luu-cau-hay-hoc-đe-on-lai" tabindex="-1">Lưu câu hay học để ôn lại <a class="header-anchor" href="#luu-cau-hay-hoc-đe-on-lai" aria-label="Permalink to “Lưu câu hay học để ôn lại”">​</a></h2><p>Một số hệ thống có chức năng <strong>Sổ tay sai</strong>:</p><ul><li>Bấm icon <strong>⭐ Lưu</strong> trên câu để thêm vào sổ tay.</li><li>Mở Sổ tay từ menu - xem lại các câu đã lưu bất cứ lúc nào.</li></ul><blockquote><p>💡 Khuyến nghị: <strong>Lưu ~20-30 câu nhớ đời</strong> từ mỗi đề lớn. Trước thi 1 tuần, đọc lại sổ tay này.</p></blockquote><h2 id="in-tai-pdf-bai-lam" tabindex="-1">In / Tải PDF bài làm <a class="header-anchor" href="#in-tai-pdf-bai-lam" aria-label="Permalink to “In / Tải PDF bài làm”">​</a></h2><ul><li>Bấm <strong>Tải PDF</strong> ở góc trên - hệ thống xuất file gồm: <ul><li>Tất cả câu hỏi + đáp án bạn chọn + đáp án đúng + lời giải.</li><li>Phù hợp để in ra giấy ôn lại.</li></ul></li></ul><h2 id="phan-tich-sau-bai-thi" tabindex="-1">Phân tích sau bài thi <a class="header-anchor" href="#phan-tich-sau-bai-thi" aria-label="Permalink to “Phân tích sau bài thi”">​</a></h2><p>Ngoài trang xem lại câu hỏi, có tab <strong>Phân tích</strong>:</p><h3 id="ty-le-đung-theo-chu-đe" tabindex="-1">Tỷ lệ đúng theo chủ đề <a class="header-anchor" href="#ty-le-đung-theo-chu-đe" aria-label="Permalink to “Tỷ lệ đúng theo chủ đề”">​</a></h3><table tabindex="0"><thead><tr><th>Chủ đề</th><th>Câu đúng / Tổng</th><th>Tỷ lệ</th><th>Đánh giá</th></tr></thead><tbody><tr><td>Hàm số</td><td>8/10</td><td>80%</td><td>✅ Tốt</td></tr><tr><td>Lượng giác</td><td>2/8</td><td>25%</td><td>⚠️ Yếu</td></tr><tr><td>Hình học</td><td>5/7</td><td>71%</td><td>✅ Khá</td></tr><tr><td>...</td><td></td><td></td><td></td></tr></tbody></table><h3 id="cau-sai-sai-nhieu-nhat-so-voi-cong-đong" tabindex="-1">Câu sai - sai nhiều nhất (so với cộng đồng) <a class="header-anchor" href="#cau-sai-sai-nhieu-nhat-so-voi-cong-đong" aria-label="Permalink to “Câu sai - sai nhiều nhất (so với cộng đồng)”">​</a></h3><ul><li>Câu mà <strong>&gt;70% học viên cùng làm đều sai</strong>.</li><li>Giáo viên thường đầu tư lời giải đặc biệt cho các câu này.</li></ul><h3 id="thoi-gian-dung-cho-tung-cau" tabindex="-1">Thời gian dùng cho từng câu <a class="header-anchor" href="#thoi-gian-dung-cho-tung-cau" aria-label="Permalink to “Thời gian dùng cho từng câu”">​</a></h3><ul><li>Câu nào bạn mất quá nhiều thời gian?</li><li>So với điểm thu được - có hiệu quả không?</li></ul><h2 id="cach-hoc-tot-nhat-voi-xem-lai" tabindex="-1">Cách học tốt nhất với &quot;Xem lại&quot; <a class="header-anchor" href="#cach-hoc-tot-nhat-voi-xem-lai" aria-label="Permalink to “Cách học tốt nhất với &quot;Xem lại&quot;”">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Quy trình 3 bước</p><ol><li><strong>Bước 1 - Đọc lời giải đáp án đúng</strong>: nắm cách suy luận chuẩn.</li><li><strong>Bước 2 - Đối chiếu với cách bạn làm</strong>: bạn sai ở bước nào? Hiểu nhầm, tính nhầm, hay không biết?</li><li><strong>Bước 3 - Ghi vào sổ tay sai</strong>: 1 câu = 1 ô (đề, đáp án đúng, bài học rút ra).</li></ol></div><div class="tip custom-block"><p class="custom-block-title">Đừng skip câu đúng tình cờ</p><ul><li>Câu bạn chọn đúng nhưng <strong>không chắc lý do</strong> → cần xem lời giải để khẳng định.</li><li>Nếu không, lần sau có thể sai.</li></ul></div><div class="tip custom-block"><p class="custom-block-title">Lập kế hoạch ôn câu yếu</p><ul><li>Sau khi phân tích, <strong>chọn 3 chủ đề yếu nhất</strong>.</li><li>Vào <a href="./luyen-tap">Luyện tập theo chuyên đề</a> → tìm chuyên đề tương ứng để ôn thêm.</li></ul></div><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Tôi không thấy lời giải dưới câu hỏi?</strong> → Tùy đề. Một số đề chỉ hiển thị <strong>đáp án đúng</strong> mà chưa có lời giải. Đặt câu hỏi trong <strong>Hỏi đáp</strong> để giáo viên giải thích.</p><p><strong>Tôi đã làm 3 lần đề này - xem lại lần nào?</strong> → Mỗi lần làm là 1 bản record riêng. Vào <strong>Lịch sử</strong> chọn đúng lần (theo ngày + điểm).</p><p><strong>Đề này tôi làm rồi nhưng giờ vào &quot;Xem lại&quot; báo lỗi?</strong> → Có thể bài quá cũ, đề đã bị admin xóa hoặc sửa. Liên hệ trung tâm.</p><p><strong>Tôi không đồng ý với đáp án của hệ thống.</strong> → Đặt câu hỏi tại chính câu đó qua <strong>Hỏi đáp</strong>. Nếu giáo viên xác nhận đề sai, sẽ điều chỉnh điểm.</p>',51)])])}const m=n(l,[["render",c]]);export{d as __pageData,m as default};
